import java.util.Scanner;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Allocate memory dynamically for the buffer based on the length of user input
        char[] buffer = new char[name.length()];
        name.getChars(0, name.length(), buffer, 0);  // Copy user input to dynamic-size buffer

        System.out.println("Hello, " + new String(buffer));
    }
}

